    <script>
    const toggleButton = document.getElementById('toggle-details');
    const copyButton = document.getElementById('copy-stacktrace');
    const stacktrace = document.getElementById('stacktrace');
    const contentContainer = document.querySelector('.content-container');

    toggleButton.addEventListener('click', () =&gt; {
        stacktrace.classList.toggle('stacktrace-hidden');
        toggleButton.textContent = stacktrace.classList.contains('stacktrace-hidden') ? 'Show Details' : 'Hide Details';

        contentContainer.style.height = 'auto';
        requestAnimationFrame(() =&gt; {
            contentContainer.style.height = contentContainer.scrollHeight + "px";
        });
    });

    copyButton.addEventListener('click', () =&gt; {
        const text = stacktrace.textContent;
        navigator.clipboard.writeText(text).then(() =&gt; {
            copyButton.textContent = 'Copied to clipboard!';
            setTimeout(() =&gt; {
                copyButton.textContent = 'Copy Stacktrace';
            }, 1500);
        }).catch(() =&gt; {
            alert('Failed to copy stacktrace.');
        });
    });

    window.addEventListener('load', () =&gt; {
        contentContainer.style.height = contentContainer.scrollHeight + "px";
    });
</script>
    <style>
    .content-container {
        width: 100%;
        max-width: 650px;
        background: white;
        border-radius: 12px;
        box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
        padding: 2rem;
        overflow: hidden;
    }

    .form-container {
        display: flex;
        flex-direction: column;
        gap: 1.5rem;
    }

    .form-title {
        font-size: 1.5rem;
        font-weight: 500;
        color: var(--text-color);
        text-align: center;
        margin: 0 0 1rem;
    }

    .button-secondary {
		background-color: var(--openmrs-logo-color);
		color: white;
		padding: 10px 20px;
		border: none;
		border-radius: 10px;
		font-size: 1rem;
		cursor: pointer;
		margin: 0.5rem 0.5rem 0 0;
	}

    .error-box {
        background: #fff0f0;
        border: 1px solid #f5c2c7;
        padding: 1rem;
        border-radius: 8px;
        color: red;
        display: flex;
        flex-direction: column;
        gap: 1rem;
        word-wrap: break-word;
        overflow-wrap: break-word;
        overflow: hidden;
    }

    .error-message {
        font-weight: bold;
        font-size: 1.1rem;
    }

    .error-description {
        font-size: 1rem;
    }

    .stacktrace-hidden {
        display: none;
        max-height: 0;
        padding: 0;
        margin: 0;
        border: none;
        overflow: hidden;
    }

    #stacktrace {
        background: #f8f9fa;
        color: var(--text-color);
        padding: 1rem;
        border-radius: 8px;
        overflow-x: auto;
        font-size: 0.9rem;
        max-height: 300px;
        margin-top: 1rem;
        border: 1px solid #ddd;
    }
</style>
    <footer class="app-footer">
      <div class="footer-content">
        <div class="footer-logo">
          <img class="logo-image" src="images/openmrslogo.png" alt="OpenMRS Logo"/>
        </div>
        <div class="footer-links">
          <a shape="rect" class="footer-link" href="https://openmrs.org" target="_blank">Website</a>
          <span class="footer-divider">|</span>
          <a shape="rect" class="footer-link" href="https://wiki.openmrs.org" target="_blank">Wiki</a>
          <span class="footer-divider">|</span>
          <a shape="rect" class="footer-link" href="https://talk.openmrs.org" target="_blank">Community</a>
        </div>
        <div class="footer-copyright">
